import{_ as a,o as n,c as s,d as t}from"./app.42cf7dba.js";const e={},o=t(`<h1 id="thread-safety" tabindex="-1"><a class="header-anchor" href="#thread-safety" aria-hidden="true">#</a> Thread Safety</h1><div class="custom-container tip"><p class="custom-container-title">TL;DR</p><p>For now:</p><div class="language-java ext-java"><pre class="language-java"><code><span class="token keyword">synchronized</span> <span class="token punctuation">(</span><span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">getMainState</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// All your operations</span>
<span class="token punctuation">}</span>
</code></pre></div></div><p>No, we are not talking about Lua threads but OS threads.</p><p>The short answer is, <strong>no</strong>, we do not guarantee thread safety. But you may safely access the Lua state across threads with a bit of external synchronization.</p><p>From Java&#39;s perspective, there are two kinds of operations that might change the Lua state:</p><ol><li>Directly manipulating the Lua state by calling any of the member methods of <code>party.iroiro.luajava.Lua</code>. (You never know what might trigger a Lua GC, so just assume all methods may change the state.)</li><li>Calling methods from the proxied objects, which will ultimately run the underlying Lua functions.</li></ol><p>The key is that we synchronize on all these state-changing operations. Currently, the library synchronizes proxied calls with the main state:</p><div class="language-java ext-java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">LuaProxy</span> <span class="token keyword">implements</span> <span class="token class-name">InvocationHandler</span> <span class="token punctuation">{</span>

    <span class="token keyword">public</span> <span class="token class-name">Object</span> <span class="token function">invoke</span><span class="token punctuation">(</span><span class="token class-name">Object</span> ignored<span class="token punctuation">,</span> <span class="token class-name">Method</span> method<span class="token punctuation">,</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> objects<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">synchronized</span> <span class="token punctuation">(</span><span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">getMainState</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// Calling the underlying Lua function</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

<span class="token punctuation">}</span>
</code></pre></div><p>If you doubt that the Lua state is to be accessed across threads, then you are responsible to synchronize on the main state whenever you operate on any of the Lua threads.</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>It is not a good API of course. But probably I will not change it in the nearly future.</p></div>`,10),c=[o];function p(l,i){return n(),s("div",null,c)}var r=a(e,[["render",p],["__file","threadsafety.html.vue"]]);export{r as default};
